const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const crypto = require('crypto');

const app = express();
const server = http.createServer(app);
const io = socketIo(server, {
  cors: {
    origin: "*",
    methods: ["GET", "POST"]
  }
});

const players = new Map();
const sessions = new Map();
const leaderboard = [];

function generateSessionToken() {
  return crypto.randomBytes(32).toString('hex');
}

function authenticatePlayer(username, password) {
  return username && username.length > 0;
}

function updateLeaderboard(username, score) {
  const existingIndex = leaderboard.findIndex(entry => entry.username === username);
  
  if (existingIndex !== -1) {
    if (score > leaderboard[existingIndex].score) {
      leaderboard[existingIndex].score = score;
    }
  } else {
    leaderboard.push({ username, score });
  }
  
  leaderboard.sort((a, b) => b.score - a.score);
  
  if (leaderboard.length > 100) {
    leaderboard.length = 100;
  }
}

io.on('connection', (socket) => {
  console.log('New client connected:', socket.id);

  socket.on('login', (data) => {
    const { username, password } = data;
    
    if (authenticatePlayer(username, password)) {
      const sessionToken = generateSessionToken();
      
      const playerData = {
        username,
        socketId: socket.id,
        sessionToken,
        score: 0,
        connectedAt: Date.now()
      };
      
      players.set(socket.id, playerData);
      sessions.set(sessionToken, socket.id);
      
      socket.emit('login_success', {
        sessionToken,
        username,
        message: 'Authentication successful'
      });
      
      io.emit('player_joined', {
        username,
        playerCount: players.size
      });
      
      console.log(`Player ${username} authenticated with session ${sessionToken}`);
    } else {
      socket.emit('login_failed', {
        message: 'Authentication failed'
      });
    }
  });

  socket.on('submit_score', (data) => {
    const { sessionToken, username, score } = data;
    
    const player = players.get(socket.id);
    
    if (player && player.sessionToken === sessionToken) {
      player.score = score;
      
      updateLeaderboard(username, score);
      
      socket.emit('score_accepted', {
        username,
        score,
        message: 'Score updated successfully'
      });
      
      io.emit('leaderboard_update', {
        leaderboard: leaderboard.slice(0, 10)
      });
      
      console.log(`Score ${score} accepted for player ${username}`);
    } else {
      socket.emit('score_rejected', {
        message: 'Invalid session'
      });
    }
  });

  socket.on('get_leaderboard', () => {
    socket.emit('leaderboard_data', {
      leaderboard: leaderboard.slice(0, 10)
    });
  });

  socket.on('player_move', (data) => {
    const { sessionToken, position, action } = data;
    
    const player = players.get(socket.id);
    
    if (player && player.sessionToken === sessionToken) {
      player.position = position;
      
      socket.broadcast.emit('player_moved', {
        username: player.username,
        position,
        action
      });
    }
  });

  socket.on('game_event', (data) => {
    const { sessionToken, eventType, eventData } = data;
    
    const player = players.get(socket.id);
    
    if (player && player.sessionToken === sessionToken) {
      io.emit('game_event_broadcast', {
        username: player.username,
        eventType,
        eventData
      });
    }
  });

  socket.on('disconnect', () => {
    const player = players.get(socket.id);
    
    if (player) {
      sessions.delete(player.sessionToken);
      players.delete(socket.id);
      
      io.emit('player_left', {
        username: player.username,
        playerCount: players.size
      });
      
      console.log(`Player ${player.username} disconnected`);
    }
  });
});

app.get('/api/leaderboard', (req, res) => {
  res.json({
    leaderboard: leaderboard.slice(0, 10)
  });
});

app.get('/api/players', (req, res) => {
  const playerList = Array.from(players.values()).map(p => ({
    username: p.username,
    score: p.score
  }));
  
  res.json({
    count: playerList.length,
    players: playerList
  });
});

const PORT = process.env.PORT || 3000;

server.listen(PORT, () => {
  console.log(`Game server running on port ${PORT}`);
});